import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer/src/core';

export class RoleplayCombatCooldownParser implements IMessageParser
{
private _weaponType = 4; // 0 sword, 1 bat, 2 axe, 3 bomb, 4 none
private _totalMs = 0;
private _remainingMs = 0;

public flush(): boolean
{
this._weaponType = 4;
this._totalMs = 0;
this._remainingMs = 0;
return true;
}

public parse(wrapper: IMessageDataWrapper): boolean
{
this._weaponType = wrapper.readInt();
this._totalMs = wrapper.readInt();
this._remainingMs = wrapper.readInt();
return true;
}

public get weaponType(): number { return this._weaponType; }
public get totalMs(): number { return this._totalMs; }
public get remainingMs(): number { return this._remainingMs; }
}
